package com.agmsolutions.fabrick_test.configurations;import lombok.Getter;import org.springframework.stereotype.Component;import org.springframework.web.client.RestClient;@Getter@Componentpublic class FabrickApiRest {    private final RestClient restClient;    public FabrickApiRest(FabrickProperties fabrickProperties) {        this.restClient = RestClient.builder()                .baseUrl(fabrickProperties.getBaseUrl())                .defaultHeader("Api-Key", fabrickProperties.getApiKey())                .defaultHeader("Auth-Schema", fabrickProperties.getAuthSchema())                .defaultHeader("Content-Type", "application/json")                .build();    }}